class CheckoutService {
  pay(totalDollars: number): Promise<void> {
    return new Promise((resolve, reject) => {
      vendorSdk.pay({ amount_cents: totalDollars * 100 }, (err: Error | null) => {
        if (err) reject(err);
        else resolve();
      });
    });
  }
}

